In Unity, you can remove grass from a terrain area in several ways depending on how the grass was added in the first place. Below are some common methods for removing grass from an area within Unity:

1. **Using Terrain Detail Tools**:
    If the grass is part of the terrain's detail layers, you can reduce or remove it by editing the terrain's paint details.

    - Select the Terrain in your scene to display the Terrain component in the Inspector.
    - Go to the Paint Details tab (brush icon with grass).
    - Select the grass texture you want to remove from the list of Detail Meshes.
    - Set the "Opacity" and "Target Strength" sliders to 0 or use the "Edit Details" -> "Remove" option.
    - Paint over the grass you want to remove.

2. **Using Terrain Data**:
    If you want to remove all instances of a grass type across the entire terrain:

    - Select the Terrain in your scene to display the Terrain component in the Inspector.
    - In the Terrain inspector, go to the "Details" section.
    - Select the grass type you want to remove and either reduce its density to 0 or use the "Edit Details" -> "Remove" option to remove that detail mesh.

3. **Using a Script**:
    If you prefer to remove grass in an area programmatically, you can write a script in C# to modify the detail layer of the terrain. Here's a basic example of how you can remove grass at a specific position and radius using a script:

    ```csharp
    using UnityEngine;

    public class RemoveGrass : MonoBehaviour
    {
        public Terrain terrain;
        public int radius = 5; // Radius of the area to remove grass from

        void RemoveGrassAtPosition(Vector3 worldPos)
        {
            int terrainLayer = 0; // Layer of the grass you want to remove (assumes 0 for simplicity)

            // Convert world position to terrain's local position
            Vector3 terrainPos = worldPos - terrain.transform.position;
            Vector2Int detailPos = new Vector2Int(
                (int)(terrainPos.x / terrain.terrainData.size.x * terrain.terrainData.detailWidth),
                (int)(terrainPos.z / terrain.terrainData.size.z * terrain.terrainData.detailHeight)
            );

            int[,] details = terrain.terrainData.GetDetailLayer(detailPos.x - radius, detailPos.y - radius, radius * 2, radius * 2, terrainLayer);

            for (int y = 0; y < details.GetLength(0); y++)
            {
                for (int x = 0; x < details.GetLength(1); x++)
                {
                    details[y, x] = 0;
                }
            }

            terrain.terrainData.SetDetailLayer(detailPos.x - radius, detailPos.y - radius, terrainLayer, details);
        }

        // Example call of the RemoveGrassAtPosition() method - Call this from another script or via an event like a button press
        void Start()
        {
            Vector3 pointToRemoveGrass = new Vector3(50, 0, 50); // Replace this with the desired world position
            RemoveGrassAtPosition(pointToRemoveGrass);
        }
    }
    ```

Please note that the above example assumes that the grass to remove is the first layer (index 0). You should adjust `terrainLayer` to match the actual layer of the grass you want to remove.

Remember to attach the script to a GameObject and assign the `terrain` variable to the actual Terrain object you want to remove the grass from.

It's also important to note that modifying the terrain data during runtime can be performance-intensive, so it's a good idea to do this only when necessary.

To draw a capsule using Gizmos in Unity, you can utilize the `OnDrawGizmos` or `OnDrawGizmosSelected` method within a script attached to a GameObject. Unity doesn't have a built-in method for drawing a capsule with Gizmos directly, but you can approximate a capsule by combining two spheres (for the top and bottom caps) and a cylinder (for the middle section).

Here's an example script that demonstrates how to draw a capsule using Gizmos. This script will draw a capsule in the Scene view whenever the GameObject it's attached to is selected:

```csharp
using UnityEngine;

public class CapsuleGizmoDrawer : MonoBehaviour
{
    public float radius = 0.5f;
    public float height = 2.0f; // Height should be greater than the diameter (radius*2) to look like a capsule.

    void OnDrawGizmosSelected()
    {
        // Drawing color
        Gizmos.color = Color.green;

        // Cache transform values for easier access
        Vector3 position = transform.position;
        Quaternion rotation = transform.rotation;
        Vector3 up = rotation * Vector3.up;

        // Set up positions and radius for spheres and a cylinder
        float halfHeight = (height - radius * 2) * 0.5f;
        Vector3 offset = up * halfHeight;

        // Draw the top and bottom spheres
        Gizmos.DrawWireSphere(position + offset, radius);
        Gizmos.DrawWireSphere(position - offset, radius);

        // Draw the connecting cylinder (approximately with lines)
        Gizmos.matrix = Matrix4x4.TRS(position, rotation, new Vector3(radius * 2, halfHeight, radius * 2));

        // Cylinder approximation using lines
        for (int angle = 0; angle < 360; angle += 10)
        {
            Vector3 from = new Vector3(Mathf.Cos(Mathf.Deg2Rad * angle), 0, Mathf.Sin(Mathf.Deg2Rad * angle));
            Vector3 to = new Vector3(Mathf.Cos(Mathf.Deg2Rad * (angle + 10)), 0, Mathf.Sin(Mathf.Deg2Rad * (angle + 10)));

            // Draw the upper edge of the cylinder
            Gizmos.DrawLine(from + Vector3.up, to + Vector3.up);

            // Draw the bottom edge of the cylinder
            Gizmos.DrawLine(from - Vector3.up, to - Vector3.up);

            // Draw lines between the top and bottom edges
            Gizmos.DrawLine(from - Vector3.up, from + Vector3.up);
        }

        // Restore Gizmos matrix
        Gizmos.matrix = Matrix4x4.identity;

        // Drawing the connecting lines between the spheres and the cylinder
        // (not truly accurate for perspective, but provides a rough visual
        // approximation of a capsule in the Scene view)
    }
}
```

This script will provide a visual approximation of a capsule. You can adjust the `radius` and `height` values in the Inspector to match the dimensions of the capsule you want to represent.

Remember to attach this script to the GameObject you want to visualize, and the capsule gizmo will show up in the Scene view when the GameObject is selected.

To convert a class into a utility class in Unity (or C# in general), which can be called from a public method, you need to follow these steps:

1. Make the class static so it doesn't require an instance to be created.
2. Make the methods inside the class static as well.
3. Publicly expose the methods you want to allow access to.

Below is the modified version of the `CapsuleGizmoDrawer` class, refactored into a utility class named `CapsuleGizmoUtility`. This class contains a static method `DrawCapsuleGizmo` that can be called from other classes to draw a capsule:

```csharp
using UnityEngine;

public static class CapsuleGizmoUtility
{
    public static void DrawCapsuleGizmo(Vector3 position, Quaternion rotation, float radius, float height, Color color)
    {
        // Ensure the height is enough to create a capsule shape.
        height = Mathf.Max(height, radius * 2.0f);

        // Drawing color
        Gizmos.color = color;

        // Cache transform values for easier access
        Vector3 up = rotation * Vector3.up;

        // Set up positions and radius for spheres and a cylinder
        float halfHeight = (height - radius * 2) * 0.5f;
        Vector3 offset = up * halfHeight;

        // Draw the top and bottom spheres
        Gizmos.DrawWireSphere(position + offset, radius);
        Gizmos.DrawWireSphere(position - offset, radius);

        // Draw the connecting cylinder (approximately with lines)
        Gizmos.matrix = Matrix4x4.TRS(position, rotation, new Vector3(radius * 2, halfHeight, radius * 2));

        // Cylinder approximation using lines
        for (int angle = 0; angle < 360; angle += 10)
        {
            Vector3 from = new Vector3(Mathf.Cos(Mathf.Deg2Rad * angle), 0, Mathf.Sin(Mathf.Deg2Rad * angle));
            Vector3 to = new Vector3(Mathf.Cos(Mathf.Deg2Rad * (angle + 10)), 0, Mathf.Sin(Mathf.Deg2Rad * (angle + 10)));

            // Draw the upper edge of the cylinder
            Gizmos.DrawLine(from + Vector3.up, to + Vector3.up);

            // Draw the bottom edge of the cylinder
            Gizmos.DrawLine(from - Vector3.up, to - Vector3.up);

            // Draw lines between the top and bottom edges
            Gizmos.DrawLine(from - Vector3.up, from + Vector3.up);
        }

        // Restore Gizmos matrix
        Gizmos.matrix = Matrix4x4.identity;
    }
}
```

Now you can call this method from any other MonoBehaviour's `OnDrawGizmos` or `OnDrawGizmosSelected` method like so:

```csharp
public class SomeScript : MonoBehaviour
{
    public float radius = 0.5f;
    public float height = 2.0f;

    void OnDrawGizmosSelected()
    {
        CapsuleGizmoUtility.DrawCapsuleGizmo(transform.position, transform.rotation, radius, height, Color.green);
    }
}
```

In this example, we've exposed the `DrawCapsuleGizmo` method, which accepts the position, rotation, radius, height, and color of the capsule you want to draw. Now this utility function can be used from any other class that needs to draw a capsule gizmo. Just make sure that you're calling the utility method from an appropriate context where Gizmos drawing is allowed, such as `OnDrawGizmos` or `OnDrawGizmosSelected`.

To modify the static utility method to accept two points defining the ends of the capsule, with a specific radius, you'll perform a calculation to determine the position, height, and orientation based on the two points. Here's how to modify the CapsuleGizmoUtility class:

```csharp
using UnityEngine;

public static class CapsuleGizmoUtility
{
    public static void DrawCapsuleGizmo(Vector3 point1, Vector3 point2, float radius, Color color)
    {
        // Calculate the position (center of the line segment connecting point1 and point2)
        Vector3 position = (point1 + point2) / 2f;

        // Calculate the height (distance between point1 and point2)
        float height = Vector3.Distance(point1, point2);
        height += radius * 2; // Include the sphere's heights at the ends

        // Calculate the rotation to align the capsule with the line segment
        Quaternion rotation = Quaternion.identity;
        if (height > 0)
        {
            rotation = Quaternion.FromToRotation(Vector3.up, point2 - point1);
        }

        // Drawing color
        Gizmos.color = color;

        // Cache transform values for easier access
        Vector3 forward = rotation * Vector3.forward;
        Vector3 up = rotation * Vector3.up;
        Vector3 right = rotation * Vector3.right;

        // Draw the top and bottom spheres
        Gizmos.DrawWireSphere(point1, radius);
        Gizmos.DrawWireSphere(point2, radius);

        // Draw the edges of the cylinder (approximation using lines)
        if (height > 0)
        {
            float halfCylinderHeight = (height - 2 * radius) * 0.5f;
            for (int i = 0; i < 360; i += 10)
            {
                // Calculate cylinder edge points in local space
                Vector3 from = new Vector3(radius * Mathf.Cos(Mathf.Deg2Rad * i), halfCylinderHeight, radius * Mathf.Sin(Mathf.Deg2Rad * i));
                Vector3 to = new Vector3(radius * Mathf.Cos(Mathf.Deg2Rad * (i + 10)), halfCylinderHeight, radius * Mathf.Sin(Mathf.Deg2Rad * (i + 10)));

                // Draw lines on the top edge of the cylinder
                Gizmos.DrawLine(position + right * from.x + up * from.y + forward * from.z, position + right * to.x + up * to.y + forward * to.z);

                // Draw lines on the bottom edge of the cylinder
                from.y = -from.y;
                to.y = -to.y;
                Gizmos.DrawLine(position + right * from.x + up * from.y + forward * from.z, position + right * to.x + up * to.y + forward * to.z);

                // Draw the vertical line between the top and bottom edges along the cylinder side
                Gizmos.DrawLine(position + right * from.x + up * from.y + forward * from.z, position + right * to.x + up * to.y + forward * to.z);
            }
        }
    }
}
```

Now the method `DrawCapsuleGizmo` takes two points that represent the ends of the capsule and the radius of the capsule. You can use this method to draw the capsule between any two points with a specified radius and color.

To use this utility method, you would call it with appropriate `point1` and `point2` values:

```csharp
public class CapsuleGizmoTest : MonoBehaviour
{
    public Vector3 point1 = new Vector3(-1, 0, 0);
    public Vector3 point2 = new Vector3(1, 0, 0);
    public float radius = 0.5f;

    void OnDrawGizmosSelected()
    {
        CapsuleGizmoUtility.DrawCapsuleGizmo(point1, point2, radius, Color.green);
    }
}
```

Attach the `CapsuleGizmoTest` script to any GameObject in your scene, and when that GameObject is selected, the capsule gizmo will be drawn between the specified points with the determined radius. Adjust the `point1`, `point2`, and `radius` fields in the Inspector panel to change the size and position of the capsule gizmo.

To create a script that launches a raycast from one point to another and checks whether there are no colliders or triggers in the way, you can write a simple script that uses Physics.Raycast, like so:

```csharp
using UnityEngine;

public class RaycastCheck : MonoBehaviour
{
    public Vector3 startPoint;
    public Vector3 endPoint;
    public LayerMask layerMask; // You can use this to selectively ignore certain layers

    void Update()
    {
        // Launch the raycast from startPoint towards endPoint
        Vector3 direction = endPoint - startPoint;
        float distance = direction.magnitude;
        direction.Normalize();

        // Check if there's a clear path (no colliders) from startPoint to endPoint
        if (Physics.Raycast(startPoint, direction, out RaycastHit hit, distance, layerMask.value, QueryTriggerInteraction.Ignore))
        {
            // Something was hit - a collider is in the way
            Debug.DrawRay(startPoint, direction * hit.distance, Color.red);
            Debug.Log("Raycast hit: " + hit.collider.name);
        }
        else
        {
            // Clear path - no colliders were hit
            Debug.DrawRay(startPoint, direction * distance, Color.green);
            Debug.Log("Clear path, no colliders detected.");
        }
    }
}
```

This script will perform a raycast from `startPoint` to `endPoint` on every `Update` call and log whether the path is clear or not. If there's a collider in the way, it will log what was hit. The `LayerMask` lets you filter out which layers the raycast should consider -- by setting this, you can ignore certain layers (such as the layer for triggers if you only want to detect actual colliders).

Attach this script to any GameObject in your scene and set the `startPoint` and `endPoint` in the Inspector or via another script.

Please note that DrawRay draws a line in the scene for visual debugging and does not affect any physics calculations. The color denotes if the path is clear (green) or obstructed (red).

By default, the `layerMask` variable should be set to affect all layers. If you want to customize it, you can do so from the Unity Inspector by selecting the appropriate layers you want the raycast to hit. This is also where you'd make the raycast ignore triggers by setting the `QueryTriggerInteraction` to `Ignore`. If you want to include triggers in your raycast result, you can change that to `QueryTriggerInteraction.Collide`.

In Unity, if you want to reference values set in another method, you generally have several options depending on your exact requirements and code structure. Below you'll find some common techniques for passing data between methods.

**1. Using Member Variables (Fields or Properties):**

One common method is to use class member variables to store the value:

```csharp
public class Example : MonoBehaviour
{
    private int myValue;

    void Start()
    {
        SetMyValue(10);
        AnotherMethod();
    }

    void SetMyValue(int newValue)
    {
        myValue = newValue;
    }

    void AnotherMethod()
    {
        Debug.Log(myValue); // Outputs 10, because SetMyValue was called in Start before AnotherMethod
    }
}
```

**2. Using Method Parameters (for Direct Calls):**

For directly calling methods, you can simply pass values as parameters:

```csharp
public class Example : MonoBehaviour
{
    void Start()
    {
        AnotherMethod(10);
    }

    void AnotherMethod(int value)
    {
        Debug.Log(value); // Outputs 10
    }
}
```

**3. Returning Values from Methods:**

If you want to get a value from another method, you can return it:

```csharp
public class Example : MonoBehaviour
{
    void Start()
    {
        int value = GetValue();
        // Use value as needed
    }

    int GetValue()
    {
        return 10; // For example, get some computed value and return it
    }
}
```

**4. Using Callbacks or Delegates:**

If you need to set a value asynchronously, you can use a callback or a delegate:

```csharp
public class Example : MonoBehaviour
{
    public delegate void ValueSetter(int value);
    public event ValueSetter OnValueSet;

    void Start()
    {
        OnValueSet += ValueReceived; // Subscribe to the event
        SetValueAsync(10);
    }

    void SetValueAsync(int value)
    {
        // Simulate an asynchronous operation
        StartCoroutine(AsyncOperation(value));
    }

    IEnumerator AsyncOperation(int value)
    {
        yield return new WaitForSeconds(1); // Wait for a second to simulate async work
        OnValueSet?.Invoke(value); // Notify subscribers that the value is set
    }

    void ValueReceived(int value)
    {
        Debug.Log(value); // Outputs 10 after 1 second
    }
}
```

These are a few patterns for setting and getting values between methods. The choice of which one to use will depend on the specific use-case in your project, such as whether you need the value instantly, if it's an asynchronous operation, or if the values are being passed within the same object or across different objects.

using System.Collections;
using Game.Systems;
using UnityEngine.UIElements;

namespace Game.ImprovedAI
{
    using System.Collections;
    using UnityEngine;

    public class Arrow : MonoBehaviour
    {
        public float speed = 10f; // Velocidad constante de la flecha
        public float maxHeightFactor = 0.25f; // Factor de la distancia que afecta la altura máxima
        public float chaseDistance;
        public float damageRange;
        public GameObject target; // Posición del objetivo

        private Vector3 startPoint;
        private float travelTime;
        private UnitHealth unitHealth;
        private float damage;


        public void Init(GameObject target, UnitHealth unitHealth, float damage)
        {
            this.target = target;
            this.unitHealth = unitHealth;
            this.damage = damage;
            startPoint = transform.position;
            InitiateFlight();
        }

        void InitiateFlight()
        {
            // Calcular la altura máxima basada en la distancia al objetivo
            float distance = Vector3.Distance(startPoint, target.transform.position);
            float maxHeight = distance * maxHeightFactor;

            // Calcular el tiempo de vuelo basado en la velocidad constante
            travelTime = distance / speed;

            // Iniciar la simulación de la trayectoria
            StartCoroutine(SimulateProjectile(maxHeight));
        }

        IEnumerator SimulateProjectile(float maxHeight)
        {
            float elapsed_time = 0;

            Vector3 currentTarget = target.transform.position;

            while (elapsed_time < travelTime)
            {
                elapsed_time += Time.deltaTime;
                float progress = elapsed_time / travelTime;

                // Interpolar la posición horizontal
                Vector3 horizontalPosition = Vector3.Lerp(startPoint, currentTarget, progress);
                // Calcular la posición vertical con una función parabólica basada en el progreso
                float height = (-4 * maxHeight * progress * (progress - 1)) + maxHeight;

                // Calcular la próxima posición
                Vector3 nextPosition = new Vector3(horizontalPosition.x, height, horizontalPosition.z);

                // Rotar la flecha hacia la dirección de movimiento
                RotateTowardsMovement(nextPosition);

                // Mover la flecha
                transform.position = nextPosition;

                if(Vector3.Distance(transform.position, target.transform.position) < chaseDistance)
                {
                    currentTarget = gameObject.transform.position;
                }

                if(Vector3.Distance(transform.position, target.transform.position) < damageRange)
                {
                    if (unitHealth != null)
                    {
                        unitHealth.TakeDamage(damage);
                    }
                }


                yield return null;
            }

            OnReachTarget();
        }

        void RotateTowardsMovement(Vector3 nextPosition)
        {
            Vector3 directionOfMovement = nextPosition - transform.position;
            if (directionOfMovement != Vector3.zero)
            {
                Quaternion rotation = Quaternion.LookRotation(directionOfMovement.normalized);
                transform.rotation = rotation;
            }
        }

        void OnReachTarget()
        {
            // Aquí se maneja el impacto o llegada al objetivo
            Destroy(gameObject); // Por ejemplo, destruir la flecha cuando impacta el objetivo
        }
    }
}

