{
    float elapsed_time = 0;
    Vector3 currentTarget = target.transform.position;

    while (elapsed_time < travelTime)
    {
        elapsed_time += Time.deltaTime;
        float progress = elapsed_time / travelTime;

        // Interpolate the horizontal position
        Vector3 horizontalPosition = Vector3.Lerp(startPoint, currentTarget, progress);

        // Calculate the parabolic height at this point in time
        // The formula uses (-4 * maxHeight) to ensure the arrow will reach maxHeight at the midpoint (progress = 0.5)
        float heightAtThisPoint = (-4 * maxHeight * progress * (progress - 1)) + maxHeight;

        // Calculate the next position using horizontal position and parabolic height
